+            }
+
+            // After all writes complete, depth should return to 0
+            // (give writer a moment to drain)
+            crate::runtime_async::sleep(std::time::Duration::from_millis(50)).await;
+            let final_depth = handle.write_queue_depth();
+            assert_eq!(
+                final_depth, 0,
